1	//! A lock-free skip list. See [`SkipList`].
2	
3	use alloc::alloc::handle_alloc_error;
4	use core::{
5	    alloc::Layout,
6	    cmp, fmt,
7	    marker::PhantomData,
8	    mem,
9	    ops::{Bound, Deref, RangeBounds},
10	    ptr,
11	    ptr::NonNull,
12	    sync::atomic::{AtomicUsize, Ordering, fence},
13	};
14	
15	use crossbeam_epoch::{self as epoch, Atomic, Collector, Guard, Shared};
16	use crossbeam_utils::CachePadded;
17	
18	use crate::{
19	    alloc_helper::Global,
20	    comparator::{BasicComparator, Comparator},
21	};
