425	/// A search result.
426	///
427	/// The result indicates whether the key was found, as well as what were the adjacent nodes to the
428	/// key on each level of the skip list.
429	struct Position<'a, K, V> {
430	    /// Reference to a node with the given key, if found.
431	    ///
432	    /// If this is `Some` then it will point to the same node as `right[0]`.
433	    found: Option<NodeRef<'a, K, V>>,
434	
435	    /// Adjacent nodes with smaller keys (predecessors).
436	    left: [TowerRef<'a, K, V>; MAX_HEIGHT],
437	
438	    /// Adjacent nodes with equal or greater keys (successors).
439	    right: [Shared<'a, Node<K, V>>; MAX_HEIGHT],
440	}
