442	/// Frequently modified data associated with a skip list.
443	struct HotData {
444	    /// The seed for random height generation.
445	    seed: AtomicUsize,
446	
447	    /// The number of entries in the skip list.
448	    len: AtomicUsize,
449	
450	    /// Highest tower currently in use. This value is used as a hint for where
451	    /// to start lookups and never decreases.
452	    max_height: AtomicUsize,
453	}
454	
455	/// A lock-free skip list.
456	// TODO(stjepang): Embed a custom `epoch::Collector` inside `SkipList<K, V>`. Instead of adding
457	// garbage to the default global collector, we should add it to a local collector tied to the
458	// particular skip list instance.
459	//
460	// Since global collector might destroy garbage arbitrarily late in the future, some skip list
461	// methods have `K: 'static` and `V: 'static` bounds. But a local collector embedded in the skip
462	// list would destroy all remaining garbage when the skip list is dropped, so in that case we'd be
463	// able to remove those bounds on types `K` and `V`.
464	//
465	// As a further future optimization, if `!mem::needs_drop::<K>() && !mem::needs_drop::<V>()`
466	// (neither key nor the value have destructors), there's no point in creating a new local
467	// collector, so we should simply use the global one.
468	pub struct SkipList<K, V, C = BasicComparator> {
469	    /// The head of the skip list (just a dummy node, not a real entry).
470	    head: Head<K, V>,
471	
472	    /// The `Collector` associated with this skip list.
473	    collector: Collector,
474	
475	    /// Hot data associated with the skip list, stored in a dedicated cache line.
476	    hot_data: CachePadded<HotData>,
477	
478	    /// The `Comparator` used to determine key ordering.
479	    comparator: C,
480	}
481	
482	unsafe impl<K: Send + Sync, V: Send + Sync, C: Send + Sync> Send for SkipList<K, V, C> {}
483	unsafe impl<K: Send + Sync, V: Send + Sync, C: Send + Sync> Sync for SkipList<K, V, C> {}
484	
485	impl<K, V> SkipList<K, V> {
486	    /// Returns a new, empty skip list.
487	    pub fn new(collector: Collector) -> Self {
488	        Self::with_comparator(collector, Default::default())
489	    }
490	}
491	
492	impl<K, V, C> SkipList<K, V, C> {
493	    /// Returns a new, empty skip list using the given comparator.
494	    pub fn with_comparator(collector: Collector, comparator: C) -> Self {
495	        Self {
496	            head: Head::new(),
497	            collector,
498	            hot_data: CachePadded::new(HotData {
499	                seed: AtomicUsize::new(1),
500	                len: AtomicUsize::new(0),
501	                max_height: AtomicUsize::new(1),
502	            }),
503	            comparator,
504	        }
505	    }
506	
507	    /// Returns `true` if the skip list is empty.
508	    pub fn is_empty(&self) -> bool {
509	        self.len() == 0
510	    }
511	
512	    /// Returns the number of entries in the skip list.
513	    ///
514	    /// If the skip list is being concurrently modified, consider the returned number just an
515	    /// approximation without any guarantees.
516	    pub fn len(&self) -> usize {
517	        let len = self.hot_data.len.load(Ordering::Relaxed);
518	
519	        // Due to the relaxed memory ordering, the length counter may sometimes
520	        // underflow and produce a very large value. We treat such values as 0.
521	        if len > isize::MAX as usize { 0 } else { len }
522	    }
523	
524	    /// Ensures that all `Guard`s used with the skip list come from the same
525	    /// `Collector`.
526	    fn check_guard(&self, guard: &Guard) {
527	        if let Some(c) = guard.collector() {
528	            assert!(c == &self.collector);
529	        }
530	    }
531	}
532	
533	impl<K, V, C> SkipList<K, V, C>
534	where
535	    C: Comparator<K>,
536	{
537	    /// Returns the entry with the smallest key.
538	    pub fn front<'a: 'g, 'g>(&'a self, guard: &'g Guard) -> Option<Entry<'a, 'g, K, V, C>> {
539	        self.check_guard(guard);
540	        let n = self.next_node(self.head.as_tower(), Bound::Unbounded, guard)?;
541	        Some(Entry {
542	            parent: self,
543	            node: n,
544	            guard,
545	        })
546	    }
547	
548	    /// Returns the entry with the largest key.
549	    pub fn back<'a: 'g, 'g>(&'a self, guard: &'g Guard) -> Option<Entry<'a, 'g, K, V, C>> {
550	        self.check_guard(guard);
551	        let n = self.search_bound::<K>(Bound::Unbounded, true, guard)?;
552	        Some(Entry {
553	            parent: self,
554	            node: n,
555	            guard,
556	        })
557	    }
558	
559	    /// Returns `true` if the map contains a value for the specified key.
560	    pub fn contains_key<Q>(&self, key: &Q, guard: &Guard) -> bool
561	    where
562	        C: Comparator<K, Q>,
563	        Q: ?Sized,
564	    {
565	        self.get(key, guard).is_some()
566	    }
567	
568	    /// Returns an entry with the specified `key`.
569	    pub fn get<'a: 'g, 'g, Q>(&'a self, key: &Q, guard: &'g Guard) -> Option<Entry<'a, 'g, K, V, C>>
570	    where
571	        C: Comparator<K, Q>,
572	        Q: ?Sized,
573	    {
574	        self.check_guard(guard);
575	        let n = self.search_bound(Bound::Included(key), false, guard)?;
576	        if !self.comparator.equivalent(&n.key, key) {
577	            return None;
578	        }
579	
580	        Some(Entry {
581	            parent: self,
582	            node: n,
583	            guard,
584	        })
585	    }
586	
587	    /// Returns an `Entry` pointing to the lowest element whose key is above
588	    /// the given bound. If no such element is found then `None` is
589	    /// returned.
590	    pub fn lower_bound<'a: 'g, 'g, Q>(
591	        &'a self,
592	        bound: Bound<&Q>,
593	        guard: &'g Guard,
594	    ) -> Option<Entry<'a, 'g, K, V, C>>
595	    where
596	        C: Comparator<K, Q>,
597	        Q: ?Sized,
598	    {
599	        self.check_guard(guard);
600	        let n = self.search_bound(bound, false, guard)?;
601	        Some(Entry {
602	            parent: self,
603	            node: n,
604	            guard,
605	        })
606	    }
607	
608	    /// Returns an `Entry` pointing to the highest element whose key is below
609	    /// the given bound. If no such element is found then `None` is
610	    /// returned.
611	    pub fn upper_bound<'a: 'g, 'g, Q>(
612	        &'a self,
613	        bound: Bound<&Q>,
614	        guard: &'g Guard,
615	    ) -> Option<Entry<'a, 'g, K, V, C>>
616	    where
617	        C: Comparator<K, Q>,
618	        Q: ?Sized,
619	    {
620	        self.check_guard(guard);
621	        let n = self.search_bound(bound, true, guard)?;
622	        Some(Entry {
623	            parent: self,
624	            node: n,
625	            guard,
626	        })
627	    }
628	
629	    /// Finds an entry with the specified key, or inserts a new `key`-`value` pair if none exist.
630	    pub fn get_or_insert(&self, key: K, value: V, guard: &Guard) -> RefEntry<'_, K, V, C> {
631	        self.insert_internal(key, || value, |_| false, guard)
632	    }
633	
634	    /// Finds an entry with the specified key, or inserts a new `key`-`value` pair if none exist,
635	    /// where value is calculated with a function.
636	    ///
637	    /// <b>Note:</b> Another thread may write key value first, leading to the result of this closure
638	    /// discarded. If closure is modifying some other state (such as shared counters or shared
639	    /// objects), it may lead to <u>undesired behaviour</u> such as counters being changed without
640	    /// result of closure inserted
