922	    /// Searches for a key in the skip list and returns a list of all adjacent nodes.
923	    fn search_position<'a, Q>(&'a self, key: &Q, guard: &'a Guard) -> Position<'a, K, V>
924	    where
925	        C: Comparator<K, Q>,
926	        Q: ?Sized,
927	    {
928	        unsafe {
929	            'search: loop {
930	                // The result of this search.
931	                let mut result = Position {
932	                    found: None,
933	                    left: [self.head.as_tower(); MAX_HEIGHT],
934	                    right: [Shared::null(); MAX_HEIGHT],
935	                };
936	
937	                // The current level we're at.
938	                let mut level = self.hot_data.max_height.load(Ordering::Relaxed);
939	
940	                // Fast loop to skip empty tower levels.
941	                while level >= 1
942	                    && self
943	                        .head
944	                        .get_level(level - 1)
945	                        .load(Ordering::Relaxed, guard)
946	                        .is_null()
947	                {
948	                    level -= 1;
949	                }
950	
951	                // The predecessor node
952	                let mut pred = self.head.as_tower();
953	
954	                while level >= 1 {
955	                    level -= 1;
956	
957	                    // Two adjacent nodes at the current level.
958	                    let mut curr = pred.get_level(level).load_consume(guard);
959	
960	                    // If `curr` is marked, that means `pred` is removed and we have to restart the
961	                    // search.
962	                    if curr.tag() == 1 {
963	                        continue 'search;
964	                    }
965	
966	                    // Iterate through the current level until we reach a node with a key greater
967	                    // than or equal to `key`.
968	                    while let Some(c) = NodeRef::from_shared(curr) {
969	                        let succ = c.get_level(level).load_consume(guard);
970	
971	                        if succ.tag() == 1 {
972	                            if let Some(c) = self.help_unlink(pred.get_level(level), c, succ, guard)
973	                            {
974	                                // On success, continue searching through the current level.
975	                                curr = c;
976	                                continue;
977	                            } else {
978	                                // On failure, we cannot do anything reasonable to continue
979	                                // searching from the current position. Restart the search.
980	                                continue 'search;
981	                            }
982	                        }
983	
984	                        // If `curr` contains a key that is greater than or equal to `key`, we're
985	                        // done with this level.
986	                        match self.comparator.compare(&c.key, key) {
987	                            cmp::Ordering::Greater => break,
988	                            cmp::Ordering::Equal => {
989	                                result.found = Some(c);
990	                                break;
991	                            }
992	                            cmp::Ordering::Less => {}
993	                        }
994	
995	                        // Move one step forward.
996	                        pred = c.as_tower();
997	                        curr = succ;
998	                    }
999	
1000	                    // Store the position at the current level into the result.
1001	                    result.left[level] = pred;
1002	                    result.right[level] = curr;
1003	                }
1004	
1005	                return result;
1006	            }
1007	        }
1008	    }
