1010	    /// Inserts an entry with the specified `key` and `value`.
1011	    ///
1012	    /// If `replace` is `true`, then any existing entry with this key will first be removed.
1013	    fn insert_internal<F, CompareF>(
1014	        &self,
1015	        key: K,
1016	        value: F,
1017	        replace: CompareF,
1018	        guard: &Guard,
1019	    ) -> RefEntry<'_, K, V, C>
1020	    where
1021	        C: Comparator<K>,
1022	        F: FnOnce() -> V,
1023	        CompareF: Fn(&V) -> bool,
1024	    {
1025	        self.check_guard(guard);
1026	
1027	        unsafe {
1028	            // Rebind the guard to the lifetime of self. This is a bit of a
1029	            // hack but it allows us to return references that are not bound to
1030	            // the lifetime of the guard.
1031	            let guard = &*(guard as *const _);
1032	
1033	            // First try searching for the key.
1034	            // Note that the `Ord` implementation for `K` may panic during the search.
1035	            let mut search = self.search_position(&key, guard);
1036	            if let Some(r) = search.found {
1037	                let replace = replace(&r.value);
1038	                if !replace {
1039	                    // If a node with the key was found and we're not going to replace it, let's
1040	                    // try returning it as an entry.
1041	                    if let Some(e) = RefEntry::try_acquire(self, r) {
1042	                        return e;
1043	                    }
1044	                }
1045	            }
1046	
1047	            // create value before creating node, so extra allocation doesn't happen if value() function panics
1048	            let value = value();
1049	            // Create a new node.
1050	            let height = self.random_height();
1051	            let (node, n) = {
1052	                // The reference count is initially two to account for:
1053	                // 1. The entry that will be returned.
1054	                // 2. The link at the level 0 of the tower.
1055	                let n = Node::<K, V>::alloc(height, 2);
1056	
1057	                // Write the key and the value into the node.
1058	                ptr::addr_of_mut!((*n).key).write(key);
1059	                ptr::addr_of_mut!((*n).value).write(value);
1060	
1061	                (
1062	                    Shared::<Node<K, V>>::from(n as *const _),
1063	                    NodeRef::new(NonNull::new_unchecked(n)),
1064	                )
1065	            };
1066	
1067	            // Optimistically increment `len`.
1068	            self.hot_data.len.fetch_add(1, Ordering::Relaxed);
1069	
1070	            loop {
1071	                // Set the lowest successor of `n` to `search.right[0]`.
1072	                n.get_level(0).store(search.right[0], Ordering::Relaxed);
1073	
1074	                // Try installing the new node into the skip list (at level 0).
1075	                // TODO(Amanieu): can we use release ordering here?
1076	                if search.left[0]
1077	                    .get_level(0)
1078	                    .compare_exchange(
1079	                        search.right[0],
1080	                        node,
1081	                        Ordering::SeqCst,
1082	                        Ordering::SeqCst,
1083	                        guard,
1084	                    )
1085	                    .is_ok()
1086	                {
1087	                    // This node has been abandoned
1088	                    if let Some(r) = search.found {
1089	                        if r.mark_tower() {
1090	                            self.hot_data.len.fetch_sub(1, Ordering::Relaxed);
1091	                        }
1092	                    }
1093	                    break;
1094	                }
1095	
1096	                // We failed. Let's search for the key and try again.
1097	                {
1098	                    // Create a guard that destroys the new node in case search panics.
1099	                    struct ScopeGuard<K, V>(*const Node<K, V>);
1100	                    impl<K, V> Drop for ScopeGuard<K, V> {
1101	                        fn drop(&mut self) {
1102	                            unsafe { Node::finalize(self.0 as *mut Node<K, V>) }
1103	                        }
1104	                    }
1105	                    let sg = ScopeGuard(node.as_raw());
1106	                    search = self.search_position(&n.key, guard);
1107	                    mem::forget(sg);
1108	                }
1109	
1110	                if let Some(r) = search.found {
1111	                    let replace = replace(&r.value);
1112	                    if !replace {
1113	                        // If a node with the key was found and we're not going to replace it,
1114	                        // let's try returning it as an entry.
1115	                        if let Some(e) = RefEntry::try_acquire(self, r) {
1116	                            // Destroy the new node.
1117	                            Node::finalize(node.as_raw() as *mut Node<K, V>);
1118	                            self.hot_data.len.fetch_sub(1, Ordering::Relaxed);
1119	
1120	                            return e;
1121	                        }
1122	
1123	                        // If we couldn't increment the reference count, that means someone has
1124	                        // just now removed the node.
1125	                    }
1126	                }
1127	            }
1128	
1129	            // The new node was successfully installed. Let's create an entry associated with it.
1130	            let entry = RefEntry {
1131	                parent: self,
1132	                node: n,
1133	            };
1134	
1135	            // Build the rest of the tower above level 0.
1136	            'build: for level in 1..height {
1137	                loop {
1138	                    // Obtain the predecessor and successor at the current level.
1139	                    let pred = search.left[level];
1140	                    let succ = search.right[level];
1141	
1142	                    // Load the current value of the pointer in the tower at this level.
1143	                    // TODO(Amanieu): can we use relaxed ordering here?
1144	                    let next = n.get_level(level).load(Ordering::SeqCst, guard);
1145	
1146	                    // If the current pointer is marked, that means another thread is already
1147	                    // removing the node we've just inserted. In that case, let's just stop
1148	                    // building the tower.
1149	                    if next.tag() == 1 {
1150	                        break 'build;
1151	                    }
1152	
1153	                    // When searching for `key` and traversing the skip list from the highest level
1154	                    // to the lowest, it is possible to observe a node with an equal key at higher
1155	                    // levels and then find it missing at the lower levels if it gets removed
1156	                    // during traversal. Even worse, it is possible to observe completely different
1157	                    // nodes with the exact same key at different levels.
1158	                    //
1159	                    // Linking the new node to a dead successor with an equal key could create
1160	                    // subtle corner cases that would require special care. It's much easier to
1161	                    // simply prohibit linking two nodes with equal keys.
1162	                    //
1163	                    // If the successor has the same key as the new node, that means it is marked
1164	                    // as removed and should be unlinked from the skip list. In that case, let's
1165	                    // repeat the search to make sure it gets unlinked and try again.
1166	                    //
1167	                    // If this comparison or the following search panics, we simply stop building
1168	                    // the tower without breaking any invariants. Note that building higher levels
1169	                    // is completely optional. Only the lowest level really matters, and all the
1170	                    // higher levels are there just to make searching faster.
1171	                    if succ
1172	                        .as_ref()
1173	                        .is_some_and(|s| self.comparator.equivalent(&s.key, &n.key))
1174	                    {
1175	                        search = self.search_position(&n.key, guard);
1176	                        continue;
1177	                    }
1178	
1179	                    // Change the pointer at the current level from `next` to `succ`. If this CAS
1180	                    // operation fails, that means another thread has marked the pointer and we
1181	                    // should stop building the tower.
1182	                    // TODO(Amanieu): can we use release ordering here?
1183	                    if n.get_level(level)
1184	                        .compare_exchange(next, succ, Ordering::SeqCst, Ordering::SeqCst, guard)
1185	                        .is_err()
1186	                    {
1187	                        break 'build;
1188	                    }
1189	
1190	                    // Increment the reference count. The current value will always be at least 1
1191	                    // because we are holding `entry`.
1192	                    n.refs_and_height
1193	                        .fetch_add(1 << HEIGHT_BITS, Ordering::Relaxed);
1194	
1195	                    // Try installing the new node at the current level.
1196	                    // TODO(Amanieu): can we use release ordering here?
1197	                    if pred
1198	                        .get_level(level)
1199	                        .compare_exchange(succ, node, Ordering::SeqCst, Ordering::SeqCst, guard)
1200	                        .is_ok()
1201	                    {
1202	                        // Success! Continue on the next level.
1203	                        break;
1204	                    }
1205	
1206	                    // Installation failed. Decrement the reference count.
1207	                    n.refs_and_height
1208	                        .fetch_sub(1 << HEIGHT_BITS, Ordering::Relaxed);
1209	
1210	                    // We don't have the most up-to-date search results. Repeat the search.
1211	                    //
1212	                    // If this search panics, we simply stop building the tower without breaking
1213	                    // any invariants. Note that building higher levels is completely optional.
1214	                    // Only the lowest level really matters, and all the higher levels are there
1215	                    // just to make searching faster.
1216	                    search = self.search_position(&n.key, guard);
1217	                }
1218	            }
1219	
1220	            // If any pointer in the tower is marked, that means our node is in the process of
1221	            // removal or already removed. It is possible that another thread (either partially or
1222	            // completely) removed the new node while we were building the tower, and just after
1223	            // that we installed the new node at one of the higher levels. In order to undo that
1224	            // installation, we must repeat the search, which will unlink the new node at that
1225	            // level.
1226	            // TODO(Amanieu): can we use relaxed ordering here?
1227	            if n.get_level(height - 1).load(Ordering::SeqCst, guard).tag() == 1 {
1228	                self.search_bound(Bound::Included(&n.key), false, guard);
1229	            }
1230	
1231	            // Finally, return the new entry.
1232	            entry
1233	        }
1234	    }
1235	}
