1237	impl<K, V, C> SkipList<K, V, C>
1238	where
1239	    C: Comparator<K>,
1240	    K: Send + 'static,
1241	    V: Send + 'static,
1242	{
1243	    /// Inserts a `key`-`value` pair into the skip list and returns the new entry.
1244	    ///
1245	    /// If there is an existing entry with this key, it will be removed before inserting the new
1246	    /// one.
1247	    pub fn insert(&self, key: K, value: V, guard: &Guard) -> RefEntry<'_, K, V, C> {
1248	        self.insert_internal(key, || value, |_| true, guard)
1249	    }
1250	
1251	    /// Inserts a `key`-`value` pair into the skip list and returns the new entry.
1252	    ///
1253	    /// If there is an existing entry with this key and compare(entry.value) returns true,
1254	    /// it will be removed before inserting the new one.
1255	    /// The closure will not be called if the key is not present.
1256	    pub fn compare_insert<F>(
1257	        &self,
1258	        key: K,
1259	        value: V,
1260	        compare_fn: F,
1261	        guard: &Guard,
1262	    ) -> RefEntry<'_, K, V, C>
1263	    where
1264	        F: Fn(&V) -> bool,
1265	    {
1266	        self.insert_internal(key, || value, compare_fn, guard)
