1269	    /// Removes an entry with the specified `key` from the map and returns it.
1270	    pub fn remove<Q>(&self, key: &Q, guard: &Guard) -> Option<RefEntry<'_, K, V, C>>
1271	    where
1272	        C: Comparator<K, Q>,
1273	        Q: ?Sized,
1274	    {
1275	        self.check_guard(guard);
1276	
1277	        unsafe {
1278	            // Rebind the guard to the lifetime of self. This is a bit of a
1279	            // hack but it allows us to return references that are not bound to
1280	            // the lifetime of the guard.
1281	            let guard = &*(guard as *const _);
1282	
1283	            loop {
1284	                // Try searching for the key.
1285	                let search = self.search_position(key, guard);
1286	
1287	                let n = search.found?;
1288	
1289	                // First try incrementing the reference count because we have to return the node as
1290	                // an entry. If this fails, repeat the search.
1291	                let entry = match RefEntry::try_acquire(self, n) {
1292	                    Some(e) => e,
1293	                    None => continue,
1294	                };
1295	
1296	                // Try removing the node by marking its tower.
1297	                if n.mark_tower() {
1298	                    // Success! Decrement `len`.
1299	                    self.hot_data.len.fetch_sub(1, Ordering::Relaxed);
1300	
1301	                    // Unlink the node at each level of the skip list. We could do this by simply
1302	                    // repeating the search, but it's usually faster to unlink it manually using
1303	                    // the `left` and `right` lists.
1304	                    for level in (0..n.height()).rev() {
1305	                        // TODO(Amanieu): can we use relaxed ordering here?
1306	                        let succ = n.get_level(level).load(Ordering::SeqCst, guard).with_tag(0);
1307	
1308	                        // Try linking the predecessor and successor at this level.
1309	                        // TODO(Amanieu): can we use release ordering here?
1310	                        if search.left[level]
1311	                            .get_level(level)
1312	                            .compare_exchange(
1313	                                Shared::from(n.ptr.as_ptr() as *const Node<K, V>),
1314	                                succ,
1315	                                Ordering::SeqCst,
1316	                                Ordering::SeqCst,
1317	                                guard,
1318	                            )
1319	                            .is_ok()
1320	                        {
1321	                            // Success! Decrement the reference count.
1322	                            n.decrement(guard);
1323	                        } else {
1324	                            // Failed! Just repeat the search to completely unlink the node.
1325	                            self.search_bound(Bound::Included(key), false, guard);
1326	                            break;
1327	                        }
1328	                    }
1329	                    return Some(entry);
1330	                } else {
1331	                    // The node has already been marked.
1332	                    n.decrement(guard);
1333	                    return None;
1334	                }
1335	            }
1336	        }
1337	    }
