1339	    /// Removes an entry from the front of the skip list.
1340	    pub fn pop_front(&self, guard: &Guard) -> Option<RefEntry<'_, K, V, C>> {
1341	        self.check_guard(guard);
1342	        loop {
1343	            let e = self.front(guard)?;
1344	            if let Some(e) = e.pin() {
1345	                if e.remove(guard) {
1346	                    return Some(e);
1347	                } else {
1348	                    e.release(guard);
1349	                }
1350	            }
1351	        }
1352	    }
