1413	impl<K, V, C> Drop for SkipList<K, V, C> {
1414	    fn drop(&mut self) {
1415	        unsafe {
1416	            let mut node = NodeRef::from_shared(
1417	                self.head
1418	                    .get_level(0)
1419	                    .load(Ordering::Relaxed, epoch::unprotected()),
1420	            );
1421	
1422	            // Iterate through the whole skip list and destroy every node.
1423	            while let Some(n) = node {
1424	                // Unprotected loads are okay because this function is the only one currently using
1425	                // the skip list.
1426	                let next = NodeRef::from_shared(
1427	                    n.get_level(0).load(Ordering::Relaxed, epoch::unprotected()),
1428	                );
1429	
1430	                // Deallocate every node.
1431	                Node::finalize(n.ptr.as_ptr());
1432	
1433	                node = next;
1434	            }
1435	        }
1436	    }
1437	}
