2266	        while let Some(node) = NonNull::new(self.node) {
2267	            unsafe {
2268	                let node = NodeRef::new(node);
2269	                // Unprotected loads are okay because this function is the only one currently using
2270	                // the skip list.
2271	                let next = node
2272	                    .get_level(0)
2273	                    .load(Ordering::Relaxed, epoch::unprotected());
2274	
2275	                // We can safely do this without deferring because references to
2276	                // keys & values that we give out never outlive the SkipList.
2277	                Node::finalize(node.ptr.as_ptr());
2278	
2279	                self.node = next.as_raw() as *mut Node<K, V>;
2280	            }
